#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_inlet_open = controller->inlet_open;
    bool previous_heater_on = controller->heater_on;
    controller_state_t previous_state = controller->state;

    /* Handle sensor timeout and invalid inputs - go to safe all-off */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT ||
        input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Update sensor freshness */
    if (input.kind == CONTROLLER_INPUT_TEMPERATURE) {
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Check for stale sensor data - go to safe all-off if either is stale > 1000ms */
    bool has_stale_sensor = false;
    if (!controller->has_valid_temperature) {
        if (input.kind == CONTROLLER_INPUT_NONE || input.kind == CONTROLLER_INPUT_TEMPERATURE) {
            /* If we had a valid temp but now don't, check staleness */
            if (controller->last_temperature_ms > 0 &&
                (controller->now_ms - controller->last_temperature_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
                has_stale_sensor = true;
            }
        }
    }
    if (!controller->has_valid_level) {
        if (input.kind == CONTROLLER_INPUT_NONE || input.kind == CONTROLLER_INPUT_LEVEL) {
            if (controller->last_level_ms > 0 &&
                (controller->now_ms - controller->last_level_ms) > CONTROLLER_SENSOR_TIMEOUT_MS) {
                has_stale_sensor = true;
            }
        }
    }

    if (has_stale_sensor) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        return output;
    }

    /* Stay in safe all-off until both sensors have been seen validly */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return output;
    }

    /* Both sensors valid - apply control policy */
    int level = controller->last_level;
    int temp = controller->last_temperature_c;

    bool inlet_open = false;
    bool heater_on = false;

    /* Low fill condition: LEVEL < 60 */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        inlet_open = true;
        heater_on = false;
    } else if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* High level - close inlet, heater state depends on temp */
        inlet_open = false;
        /* If level is high but we're not in the heating band, keep safe idle */
        if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            heater_on = true;
        } else {
            heater_on = false;
        }
    } else {
        /* 60 <= LEVEL <= 75 - apply temperature-based control */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temp in safe level range: close inlet, turn on heater */
            inlet_open = false;
            heater_on = true;
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 45 <= TEMP < 47: hold previous safe heater state */
            inlet_open = false;
            /* Preserve the previous heater state */
            heater_on = previous_heater_on;
        } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 47 <= TEMP <= 48: check if temperature is rising */
            bool is_rising = false;
            if (controller->previous_temperature_c > 0) {
                is_rising = controller->last_temperature_c > controller->previous_temperature_c;
            }
            if (is_rising) {
                /* Temperature rising: turn off heater early */
                inlet_open = false;
                heater_on = false;
            } else {
                /* Temperature not rising: hold previous safe heater state */
                inlet_open = false;
                heater_on = previous_heater_on;
            }
        } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 48: close inlet and turn off heater */
            inlet_open = false;
            heater_on = false;
        } else {
            /* Default safe state for unexpected conditions */
            inlet_open = false;
            heater_on = false;
        }
    }

    controller->inlet_open = inlet_open;
    controller->heater_on = heater_on;

    if (previous_inlet_open != inlet_open || previous_heater_on != heater_on) {
        output.changed = true;
    }

    output.inlet_open = inlet_open;
    output.heater_on = heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

